@push('scripts')<script src="https://cdn.jsdelivr.net/npm/select2@4.1.0-rc.0/dist/js/select2.min.js"></script><script>
function syncMealOptions(form){const option=form.querySelector('.subscription-select')?.selectedOptions[0];if(!option)return;['breakfast','lunch','dinner'].forEach(meal=>{const input=form.querySelector('[name='+meal+'_required]');const subscribed=option.dataset[meal]==='1';input.disabled=!subscribed;if(!subscribed)input.checked=false})}document.querySelectorAll('.meal-hold-form').forEach(form=>{const select=form.querySelector('.subscription-select');select?.addEventListener('change',()=>syncMealOptions(form));syncMealOptions(form)});
const summaries=@json($subscriptionSummaries);const createForm=document.getElementById('createHoldForm');const subscriptionSelect=createForm.querySelector('.create-subscription-select');let previewData=null;let previewTimer=null;
$(subscriptionSelect).select2({dropdownParent:$('#addHold'),width:'100%',placeholder:'Search customer name, mobile, or subscription…'}).on('change',()=>{syncCreateForm();schedulePreview()});
function selectedSummary(){return summaries[subscriptionSelect.value]||null}function syncCreateForm(){const summary=selectedSummary();const card=document.getElementById('customerSummary');card.classList.toggle('d-none',!summary);if(!summary)return;card.querySelectorAll('[data-summary]').forEach(el=>el.textContent=summary[el.dataset.summary]);createForm.querySelectorAll('.hold-date-input').forEach(input=>{input.min=summary.start_iso;input.max=summary.end_iso});document.querySelectorAll('.meal-status-card').forEach(card=>{const active=!!summary.meal_flags[card.dataset.meal];card.classList.toggle('d-none',!active);card.querySelectorAll('input').forEach(input=>input.disabled=!active)})}
function syncMode(){const range=createForm.elements.selection_mode.value==='range';document.getElementById('singleDateFields').classList.toggle('d-none',range);document.getElementById('rangeDateFields').classList.toggle('d-none',!range);createForm.elements.hold_date.required=!range;createForm.elements.from_date.required=range;createForm.elements.to_date.required=range;updateSelectedDays();schedulePreview()}function updateSelectedDays(){if(createForm.elements.selection_mode.value!=='range'){document.getElementById('totalSelectedDays').textContent='1';return}const from=createForm.elements.from_date.value,to=createForm.elements.to_date.value;const days=from&&to?Math.max(0,Math.round((new Date(to)-new Date(from))/86400000)+1):0;document.getElementById('totalSelectedDays').textContent=days}
document.querySelectorAll('.hold-mode').forEach(input=>input.addEventListener('change',syncMode));createForm.querySelectorAll('input').forEach(input=>input.addEventListener('change',()=>{updateSelectedDays();schedulePreview()}));function schedulePreview(){clearTimeout(previewTimer);previewTimer=setTimeout(loadPreview,250)}
async function loadPreview(){previewData=null;const summary=selectedSummary();const mode=createForm.elements.selection_mode.value;const from=mode==='single'?createForm.elements.hold_date.value:createForm.elements.from_date.value;const to=mode==='single'?from:createForm.elements.to_date.value;if(!summary||!from||!to)return showPreviewMessage('Complete the customer and date selection.');for(const meal of ['breakfast','lunch','dinner'])if(summary.meal_flags[meal]&&!createForm.querySelector('[name='+meal+'_status]:checked'))return showPreviewMessage('Choose a status for every active meal.');document.getElementById('previewStatus').textContent='Loading preview…';try{const response=await fetch('{{ route('meal-holds.preview') }}',{method:'POST',headers:{'X-CSRF-TOKEN':document.querySelector('meta[name=csrf-token]').content,'Accept':'application/json'},body:new FormData(createForm)});const result=await response.json();if(!response.ok)throw new Error(Object.values(result.errors||{}).flat()[0]||'Unable to preview these dates.');previewData=result;document.getElementById('previewStatus').textContent=result.total_days+' day(s) · '+result.compensation_days+' compensation day(s)';document.getElementById('holdPreviewBody').innerHTML=result.rows.map(row=>`<tr><td>${row.date}</td><td>${row.day}</td>${['breakfast','lunch','dinner'].map(meal=>`<td><span class="badge ${row[meal]==='Required'?'status-active':row[meal]==='Holiday'?'status-paused':'status-pending'}">${row[meal]}</span></td>`).join('')}<td>${row.counted?'<span class="text-success">Yes</span>':'No'}</td><td>${row.compensation?'<span class="text-warning fw-bold">Yes</span>':'No'}</td></tr>`).join('')}catch(error){showPreviewMessage(error.message)}}function showPreviewMessage(message){document.getElementById('previewStatus').textContent=message;document.getElementById('holdPreviewBody').innerHTML='<tr><td colspan="7" class="text-center text-muted py-4">'+message+'</td></tr>'}
createForm.addEventListener('submit',event=>{event.preventDefault();if(!createForm.checkValidity()){createForm.reportValidity();return}if(!previewData){loadPreview();return}const allFull=previewData.full_hold_days===previewData.total_days;document.getElementById('holdConfirmationMessage').textContent=allFull?`You are adding full-day meal holds for ${previewData.total_days} day(s). ${previewData.compensation_days} compensation day(s) will be added to the subscription.`:`You are adding meal holds for ${previewData.total_days} day(s). ${previewData.compensation_days} compensation day(s) will be added after accounting for complete no-meal days and holidays.`;const addModal=bootstrap.Modal.getInstance(document.getElementById('addHold'));document.getElementById('addHold').addEventListener('hidden.bs.modal',()=>bootstrap.Modal.getOrCreateInstance(document.getElementById('holdConfirmation')).show(),{once:true});addModal.hide()});document.getElementById('confirmHoldSave').addEventListener('click',()=>createForm.submit());document.getElementById('backToHoldForm').addEventListener('click',()=>{const confirm=bootstrap.Modal.getInstance(document.getElementById('holdConfirmation'));document.getElementById('holdConfirmation').addEventListener('hidden.bs.modal',()=>bootstrap.Modal.getOrCreateInstance(document.getElementById('addHold')).show(),{once:true});confirm.hide()});syncMode();
</script>@endpush
